import itertools
import logging
from typing import Iterable, List, Sequence, Optional, Any, Set

from geosat.cloud import PointCloud
from geosat.psanp.abstractions.classifier import Classifier, IClassifier
from geosat.psanp.abstractions.option import Option
from geosat.psanp.abstractions.pipelinemetadata import PipelineMetadata
from geosat.psanp.abstractions.stage import Stage
from geosat.psanp.abstractions.stages import get_stage

logger = logging.getLogger(__name__)


def _to_stages(obj: Any) -> List[Stage]:
    stages: List[Stage] = []
    for i, stage_opts in enumerate(obj, 1):
        try:
            stage_name = stage_opts["name"]
        except KeyError:
            raise KeyError(f"Missing key 'name' for stage {i}: {stage_opts}")
        if not isinstance(stage_name, str):
            raise ValueError(
                f"Invalid type {type(stage_name)} for the 'name' attribute "
                f"of stage {i}: {stage_name}"
            )
        try:
            stage_cls = get_stage(stage_name)
        except KeyError as exception:
            raise KeyError(f"No Stage named {stage_name} is available") from exception

        logger.debug("Creating stage %s with options:\n%s", stage_name, stage_opts)

        stages.append(stage_cls.from_options(stage_opts))
    return stages


class SequenceClassifier(Classifier):
    """A stage that contains other stages"""

    def __init__(
        self,
        stages: Sequence[Stage] = (),
        stage_name: Optional[str] = None,
    ) -> None:
        super().__init__(stage_name=stage_name)
        self.stages: List[Stage] = list(stages)

    def input_classes(self) -> Set[str]:
        return {
            class_name
            for stage in self.stages
            if isinstance(stage, IClassifier)
            for class_name in stage.input_classes()
        }

    def output_classes(self) -> Set[str]:
        return {
            class_name
            for stage in self.stages
            if isinstance(stage, IClassifier)
            for class_name in stage.output_classes()
        }

    @classmethod
    def options(cls) -> List[Option]:
        return [
            Option(
                "stages",
                description="A sequence of stages to launch",
                type_cast=_to_stages,
                required=True,
            ),
        ]

    def execute_on(
        self, cloud: PointCloud, pipeline_metadata: PipelineMetadata
    ) -> Iterable[PointCloud]:
        clouds: Iterable[PointCloud] = (cloud,)
        for stage in self.stages:
            logger.info(f"Executing stage: '{stage.__class__.__name__}'")
            cloud_iterators: List[Iterable[PointCloud]] = [
                stage.execute_on(cloud, pipeline_metadata) for cloud in clouds
            ]
            clouds = itertools.chain.from_iterable(cloud_iterators)
        return clouds
